def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.full_like(bins, -np.inf, dtype=float)
    for i in range(len(bins)):
        capacity = bins[i]
        if capacity <= 0:
            continue
        ratio = item / capacity
        score = 0.0
        if ratio > 4:
            score -= 200 * (ratio - 4)**4 + 50 * np.log(ratio)
        elif 3 < ratio <= 4:
            score -= 80 * (ratio - 3)**3 + 20 * (4 - ratio)**2
        elif 2 < ratio <= 3:
            for j in range(1, 4):
                score -= (25 * (ratio - 2)**j) / (j + 0.5)
            score += 15 * np.tanh(5 - ratio)
        elif 1 < ratio <= 2:
            if ratio < 1.5:
                for k in range(5):
                    score += ((-1)**k) * np.sin(ratio * np.pi * (k+1)) / ((k+1)**1.1)
            else:
                score -= 30 * (ratio - 1.5)**2 + 10 * (2 - ratio)
        else:
            segments = 10
            increment = 1.0 / segments
            for seg in range(segments):
                threshold = increment * (seg+1)
                distance = abs(ratio - threshold)
                if distance < increment:
                    score += (segments - seg)**3 / (distance + 1e-10)
                    break
            else:
                score += 10 * (1 - ratio)**2 + 5 * np.cos(ratio * 25)
        penalty = 0
        for x in range(1, 7):
            base = ((-1)**x) * (ratio ** (2.5 * x)) / (x * 2)
            if x % 3 == 0:
                penalty += base * np.log1p(x * ratio)
            elif x % 2 == 0:
                penalty += base / (1 + np.exp(-x * ratio))
            else:
                penalty -= base * np.sin(x * ratio)
        score += penalty
        if item > capacity:
            score -= 120
            for m in range(1, 7):
                if capacity == 0:
                    break
                mod_val = (item * m) % (capacity + 1)
                score += (mod_val ** 0.6) / m
                if mod_val > capacity * 0.6:
                    score -= 25 / m
        elif (capacity - item) < 0.15 * capacity:
            score += 25
            for n in range(4):
                if capacity == 0:
                    break
                score += (capacity - item) * np.cos((n+1) * ratio * np.pi * 1.5) / (n+1)
        else:
            if ratio < 0.2:
                score -= 10 * np.exp(-ratio*20) + 4 * np.cos(ratio * 30)
                for p in range(1, 5):
                    score += np.sin(ratio * np.pi * p * 1.2) / (p**1.8)
        if capacity % 7 == 0:
            score += 3 * (np.log1p(capacity) - ratio) + np.sqrt(capacity)
        elif capacity % 4 == 0:
            score -= 4 * np.sqrt(abs(ratio - 0.4))
            for s in range(1, 3):
                score += s * np.sin(ratio * s * np.pi / 2)
        else:
            for q in range(1, 8):
                if (capacity + q) % 3 == 0:
                    score += 0.7 * q / (1 + ratio * q)
                else:
                    score -= 0.2 * q * np.cos(ratio * q)
        if i % 2 == 0:
            adjustment = 0
            for z in range(1, 5):
                adjustment += ((-1)**z) * np.exp(-z*ratio) * np.cos(i * z)
            score += adjustment
        else:
            score -= np.abs(np.sin(item * ratio + i)) * 5
        priorities[i] = score
    finite_priorities = priorities[np.isfinite(priorities)]
    if finite_priorities.size == 0:
        return priorities
    max_priority = np.max(finite_priorities)
    min_priority = np.min(finite_priorities)
    if max_priority == min_priority:
        return np.where(np.isfinite(priorities), 1.0, -np.inf)
    else:
        normalized = (priorities - min_priority) / (max_priority - min_priority)
        return np.where(np.isfinite(priorities), normalized, -np.inf)
